VALUES
  (gen_random_uuid(), 'Dramatic Reveal', 'dramatic-reveal', 'Cinematic fade and reveal — heading appears fullscreen, bullets slide up one-by-one', '{"version":1,"background":{"color":"#0a0a0f","image":null,"video":null,"overlay":null},"interaction":{"mode":"tap-to-advance","autoPlayDelay":null,"showProgress":true},"typography":{"fontFamily":"''SF Pro Text'', -apple-system, sans-serif","fontSize":17,"color":"rgba(255,255,255,0.9)","lineHeight":1.6},"elements":{"h1":{"style":{"fontSize":32,"fontWeight":"bold","textAlign":"center","color":"#ffffff"},"enter":{"type":"fade","duration":800,"easing":"ease-out"},"exit":{"type":"fade","duration":400},"display":"fullscreen"},"h2":{"style":{"fontSize":24,"fontWeight":"bold","textAlign":"center"},"enter":{"type":"fade","duration":600,"easing":"ease-out"},"exit":{"type":"fade","duration":300}},"p":{"style":{},"enter":{"type":"slide-up","duration":600,"easing":"ease-out"},"exit":{"type":"fade","duration":300}},"li":{"style":{},"enter":{"type":"slide-up","duration":500,"stagger":300,"easing":"ease-out"},"exit":{"type":"fade","duration":300}},"verse":{"style":{"fontSize":18,"lineHeight":1.8},"enter":{"type":"fade","duration":600,"stagger":300},"exit":{"type":"fade","duration":300}},"verse-number":{"style":{"fontSize":12,"opacity":0.5,"fontWeight":"bold"}},"verse-reference":{"style":{"fontSize":14,"textTransform":"uppercase","letterSpacing":2},"enter":{"type":"fade","duration":400}}},"sequences":[{"match":"h1","phase":"solo","pauseAfter":true},{"match":"h2","phase":"solo","pauseAfter":true},{"match":"li","phase":"group","stagger":300,"pauseAfter":true},{"match":"verse","phase":"group","stagger":300,"pauseAfter":true},{"match":"p","phase":"solo","pauseAfter":false}]}', true, true, now(), now()),

